  "userdoc": {
    "kind": "user",
    "methods": {
      "isParticipant(uint256,uint256)": {
        "notice": "Check if a specific tokenId participated in a problem (for verifier eligibility)"
      },
      "resolveByOracle(uint256,bytes32)": {
        "notice": "Oracle fallback resolution — only when verify phase is over and no verifier consensus"
      },
      "resolveByVerifiers(uint256,bytes32)": {
        "notice": "Resolve using verifier consensus. Called by VerifierElection."
      },
      "revealAnswer(uint256,uint256,string)": {
        "notice": "Reveal the plaintext answer. Contract verifies hash matches."
      },
      "revealedAnswerCount(uint256,bytes32)": {
        "notice": "problemId => answerHash => count of agents who revealed this answer"
      },
      "submissionIndex(uint256,uint256)": {
        "notice": "problemId => tokenId => submission index + 1 (0 = not submitted)"
      },
      "winners(uint256,uint256)": {
        "notice": "problemId => winner tokenIds"
      }
    },
    "notice": "4-phase problem lifecycle: Submit → Reveal → Verify → Resolve   Phase 1 - SUBMIT (5 min): Agents submit keccak256(answer) on-chain   Phase 2 - REVEAL (2 min): Agents reveal plaintext, contract verifies hash   Phase 3 - VERIFY (3 min): Elected verifiers vote on correct answer (commit-reveal)   Phase 4 - RESOLVE: Consensus determines winners; oracle fallback if no quorum",
    "version": 1
  }
